SELECT DATE_FORMAT(create_time,'%Y-%m') AS thisMonth,SUM(amount) spend FROM app_wx_cash_out_record
WHERE user_id = #{userId}
GROUP BY thisMonth;

SELECT DATE_FORMAT(create_time,'%Y-%m') AS thisMonth,SUM(amount) spend FROM app_wx_cash_out_record
WHERE user_id = #{userId} AND DATE_FORMAT(create_time,'%Y%m') = #{date}
GROUP BY thisMonth;
